import { useState } from "react";
import { saveVitals } from "../services/api";
import { useNavigate } from "react-router-dom";

function Vitals() {
  const userId = localStorage.getItem("user_id");
  const navigate = useNavigate();

  // ----------- STATES -----------
  const [height, setHeight] = useState("");
  const [weight, setWeight] = useState("");
  const [glucose, setGlucose] = useState("");

  const [systolicBp, setSystolicBp] = useState("");
  const [diastolicBp, setDiastolicBp] = useState("");

  const [heartRate, setHeartRate] = useState("");
  const [spo2, setSpo2] = useState("");
  const [temperature, setTemperature] = useState("");

  // ----------- BMI CALCULATION -----------
  const bmi =
    height && weight
      ? (weight / ((height / 100) ** 2)).toFixed(2)
      : "";

  // ----------- SAVE HANDLER -----------
  const handleSave = async () => {
    if (
      !height || !weight || !glucose ||
      !systolicBp || !diastolicBp ||
      !heartRate || !spo2 || !temperature
    ) {
      alert("⚠️ Please fill all vitals");
      return;
    }

    try {
      await saveVitals({
        user_id: userId,
        height: Number(height),
        weight: Number(weight),
        glucose: Number(glucose),
        bmi: Number(bmi),
        systolic_bp: Number(systolicBp),
        diastolic_bp: Number(diastolicBp),
        heart_rate: Number(heartRate),
        spo2: Number(spo2),
        temperature: Number(temperature),
      });

      alert("✅ Vitals saved successfully");
      navigate("/consult");
    } catch (error) {
      console.error(error.response?.data || error);
      alert("❌ Failed to save vitals");
    }
  };

  // ----------- UI -----------
  return (
    <div style={{ maxWidth: "420px", margin: "auto" }}>
      <h2>🩺 Enter Your Vitals</h2>

      <input
        placeholder="Height (cm)"
        value={height}
        onChange={(e) => setHeight(e.target.value)}
      />

      <input
        placeholder="Weight (kg)"
        value={weight}
        onChange={(e) => setWeight(e.target.value)}
      />

      <input
        placeholder="Glucose (mg/dL)"
        value={glucose}
        onChange={(e) => setGlucose(e.target.value)}
      />

      <input
        placeholder="Systolic BP (e.g. 120)"
        value={systolicBp}
        onChange={(e) => setSystolicBp(e.target.value)}
      />

      <input
        placeholder="Diastolic BP (e.g. 80)"
        value={diastolicBp}
        onChange={(e) => setDiastolicBp(e.target.value)}
      />

      <input
        placeholder="Heart Rate (bpm)"
        value={heartRate}
        onChange={(e) => setHeartRate(e.target.value)}
      />

      <input
        placeholder="SpO₂ (%)"
        value={spo2}
        onChange={(e) => setSpo2(e.target.value)}
      />

      <input
        placeholder="Temperature (°C)"
        value={temperature}
        onChange={(e) => setTemperature(e.target.value)}
      />

      <p><b>BMI:</b> {bmi}</p>

      <button
        onClick={handleSave}
        style={{
          marginTop: "10px",
          padding: "10px",
          width: "100%",
          background: "#4f46e5",
          color: "white",
          border: "none",
          borderRadius: "6px",
          fontSize: "16px",
          cursor: "pointer"
        }}
      >
        💾 Save Vitals
      </button>
    </div>
  );
}

export default Vitals;
